// Valida entrada e normaliza ticket_id para memória Redis
const body = $input.item.json.body || $input.item.json;
const question = (body.question || body.pergunta || '').trim();

if (!question) {
  throw new Error('Campo "question" é obrigatório.');
}

// ticket_id: usa o fornecido ou gera um ID de sessão temporário
const ticket_id = String(body.ticket_id || `session-${Date.now()}`);

return {
  question,
  ticket_id,
  timestamp: new Date().toISOString()
};

