// ============================================================
// MONTAR PROMPT DINÂMICO — MarIA V3
// Injeta: categoria + memória Redis + Top 5 RAG estruturado
// ============================================================

// 1. Dados da pergunta
const { question, ticket_id, timestamp } = $('Validar Entrada').item.json;

// 2. Categoria do classificador
let categoria = 'OUTROS';
let confiancaCategoria = 0;
try {
  const classContent = $('Classificar Ticket').item.json.choices[0].message.content;
  // Remove possível markdown (```json ... ```)
  const cleanJson = classContent.replace(/```json?\s*/gi, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleanJson);
  categoria = parsed.categoria || 'OUTROS';
  confiancaCategoria = parsed.confianca || 0;
} catch (e) {
  // Fallback silencioso — categoria permanece OUTROS
}

// 3. Memória Redis (histórico da conversa)
let memoriaContexto = '';
try {
  const redisResult = $('Redis GET — Buscar Memória').item.json;
  if (redisResult.result) {
    const memoria = JSON.parse(redisResult.result);
    const historico = (memoria.historico || []).slice(-5); // últimas 5 interações
    if (historico.length > 0) {
      memoriaContexto = historico.map((h, i) =>
        `[${i + 1}] Pergunta: ${h.pergunta}\n    Resposta resumida: ${h.resposta_resumo}`
      ).join('\n');
    }
    // Dados extraídos anteriormente (IDs, produto, etc.)
    const dadosExtras = memoria.dados_extraidos || {};
    if (Object.keys(dadosExtras).length > 0) {
      memoriaContexto += `\n\nDados já coletados:\n${JSON.stringify(dadosExtras, null, 2)}`;
    }
  }
} catch (e) {
  // Sem memória prévia — primeira interação
}

// 4. Top 5 tickets similares do Pinecone (RAG estruturado)
const matches = $('Buscar Tickets Similares').item.json.matches || [];
let contextoRAG = '';
if (matches.length > 0) {
  contextoRAG = matches.map((m, i) => {
    const meta = m.metadata || {};
    const score = Math.round(m.score * 100);
    return [
      `[Ticket ${i + 1} — Similaridade: ${score}% | Categoria: ${meta.categoria || 'N/A'}]`,
      `Problema: ${meta.problema || 'N/A'}`,
      meta.solucao ? `Solução aplicada: ${meta.solucao}` : '',
      meta.tags ? `Tags: ${meta.tags}` : ''
    ].filter(Boolean).join('\n');
  }).join('\n\n---\n\n');
} else {
  contextoRAG = 'Nenhum ticket similar encontrado na base histórica.';
}

// 5. Monta o userPrompt com todos os contextos
const userPrompt = [
  `CATEGORIA DETECTADA: ${categoria} (confiança: ${confiancaCategoria}%)`,
  '',
  memoriaContexto
    ? `HISTÓRICO DA CONVERSA (ticket ${ticket_id}):\n${memoriaContexto}`
    : `HISTÓRICO DA CONVERSA: primeira interação neste ticket`,
  '',
  `CASOS SEMELHANTES DO ZENDESK (RAG):\n\n${contextoRAG}`,
  '',
  `PERGUNTA DO ATENDENTE:\n${question}`,
  '',
  'Responda seguindo a estrutura obrigatória do MarIA V3.'
].join('\n');

return {
  userPrompt,
  question,
  ticket_id,
  categoria,
  confiancaCategoria,
  ticketsEncontrados: matches.length,
  temMemoria: memoriaContexto.length > 0
};

// Extrai resposta e prepara para salvar na memória
const gptResponse = $input.item.json;
const promptData = $('Montar Prompt MarIA V3').item.json;

const resposta = gptResponse.choices[0].message.content;

// Extrai um resumo da resposta para a memória (primeira seção ✅)
const matchResposta = resposta.match(/##\s*✅\s*RESPOSTA DIRETA\s*\n([\s\S]*?)(?:\n##|$)/);
const resumo = matchResposta ? matchResposta[1].trim().substring(0, 200) : resposta.substring(0, 200);

return {
  sucesso: true,
  resposta: resposta,
  resumo_para_memoria: resumo,
  metadados: {
    pergunta_original: promptData.question,
    ticket_id: promptData.ticket_id,
    categoria: promptData.categoria,
    confianca_categoria: promptData.confiancaCategoria,
    tickets_utilizados: promptData.ticketsEncontrados,
    tinha_memoria: promptData.temMemoria,
    modelo: 'gpt-4o',
    tokens_usados: gptResponse.usage?.total_tokens || 0,
    timestamp: new Date().toISOString()
  }
};

// Monta o novo estado da memória Redis para salvar
const respostaData = $('Formatar Resposta').item.json;
const { ticket_id, pergunta_original, resumo_para_memoria } = {
  ticket_id: respostaData.metadados.ticket_id,
  pergunta_original: respostaData.metadados.pergunta_original,
  resumo_para_memoria: respostaData.resumo_para_memoria
};

// Busca memória existente para acumular
let memoriaExistente = { historico: [], dados_extraidos: {} };
try {
  const redisResult = $('Redis GET — Buscar Memória').item.json;
  if (redisResult.result) {
    memoriaExistente = JSON.parse(redisResult.result);
  }
} catch (e) {}

// Adiciona nova interação ao histórico
const novaInteracao = {
  pergunta: pergunta_original,
  resposta_resumo: resumo_para_memoria,
  categoria: respostaData.metadados.categoria,
  timestamp: respostaData.metadados.timestamp
};

memoriaExistente.historico = [
  ...(memoriaExistente.historico || []),
  novaInteracao
].slice(-10); // mantém últimas 10 interações

// TTL: 24 horas (86400 segundos) — memória expira no fim do dia
const redisKey = `maria:ticket:${ticket_id}`;
const redisValue = JSON.stringify(memoriaExistente);

return {
  redis_key: redisKey,
  redis_value: redisValue,
  ticket_id
};
